import{_ as t,o as a,c as i,a3 as s}from"./chunks/framework.DG2GXa4n.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1781013972000}'),o={name:"guide/introduction.md"};function n(r,e,d,l,c,h){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="the-problem" tabindex="-1">The problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The problem&quot;">​</a></h2><p>Almost every app does the same dance around data: kick off a request, track whether it&#39;s loading, catch the error, show the result. Then reality piles on — the user double-clicks, a second request races the first, the response is already stale, you want a retry, you&#39;d like to not refetch what you just fetched, and ideally none of this lives inside a React component.</p><p>Hand-rolled, that&#39;s a swamp of <code>useState</code>/<code>useEffect</code>, race conditions, and logic welded to the view. effector solves the <em>state</em> part beautifully with events, stores and effects. <strong>effector-refetch</strong> owns the <em>data-fetching</em> part on top of it.</p><h2 id="the-idea-build-on-real-effects" tabindex="-1">The idea: build on real effects <a class="header-anchor" href="#the-idea-build-on-real-effects" aria-label="Permalink to &quot;The idea: build on real effects&quot;">​</a></h2><p>The core decision is simple: <strong>your effect is the unit of work.</strong></p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> fetchUserFx</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> createEffect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">((</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> api.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">user</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(id));</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> userQuery</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> createQuery</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ effect: fetchUserFx });</span></span></code></pre></div><p><code>userQuery</code> is a thin reactive shell around <code>fetchUserFx</code>. It adds <code>$data</code>, <code>$error</code>, <code>$status</code>, <code>$pending</code>, lifecycle events, retry, cache and concurrency — but the effect underneath is still your effect: visible in devtools, composable with <code>attach</code>, and fork-friendly for SSR and tests. Nothing is hidden in a private executor.</p><p>That&#39;s the difference from a &quot;black box&quot; data layer: you keep effector&#39;s mental model (events flow through a graph of rules) and just get the querying conveniences declaratively.</p><h2 id="what-you-get" tabindex="-1">What you get <a class="header-anchor" href="#what-you-get" aria-label="Permalink to &quot;What you get&quot;">​</a></h2><ul><li><strong>Status &amp; lifecycle</strong> — <code>$data / $error / $status / $pending</code>, <code>finished.{done,fail}</code>.</li><li><strong>Concurrency</strong> — <code>TAKE_LATEST</code> (default), <code>TAKE_FIRST</code>, <code>TAKE_EVERY</code>; races just die.</li><li><strong>Retry</strong> — graph-level, each attempt a real effect call.</li><li><strong>Caching</strong> — staleAfter, SWR, GC, dedupe, persistence.</li><li><strong>Real cancellation</strong> — abort the in-flight request, not just ignore it.</li><li><strong>Mutations &amp; invalidation</strong> — <code>createMutation</code>, <code>invalidate</code>, <code>update</code>, optimistic updates.</li><li><strong>Validation</strong> — schema contracts (zod / Standard Schema) turn bad responses into errors.</li><li><strong>Declarative HTTP</strong> — <code>createJsonQuery</code> over the global <code>fetch</code>.</li><li><strong>Pagination</strong> — <code>createInfiniteQuery</code>.</li><li><strong>Bindings</strong> — <code>useUnit(query)</code> in React and Vue.</li></ul><h2 id="philosophy" tabindex="-1">Philosophy <a class="header-anchor" href="#philosophy" aria-label="Permalink to &quot;Philosophy&quot;">​</a></h2><ul><li><strong>Friendly by default, powerful underneath.</strong> Inline options cover the 90%; the same features are standalone operators for the rest.</li><li><strong>No magic.</strong> It&#39;s plain effector units (<code>createStore</code> / <code>sample</code> / <code>createEffect</code>) you could have written — just composed for you.</li><li><strong>Honest.</strong> We tell you when <em>not</em> to use it, and how it compares to <a href="/effector-query/guide/vs-farfetched">farfetched</a>.</li></ul><p>Ready? <a href="/effector-query/guide/getting-started">Get started →</a></p>`,14)])])}const f=t(o,[["render",n]]);export{u as __pageData,f as default};
